import React, { useState } from 'react';
import { db, storage } from '../firebase'; 
import { collection, addDoc, serverTimestamp } from 'firebase/firestore';
import { ref, uploadBytes, getDownloadURL } from 'firebase/storage';
import { X, Camera, Send, Loader2 } from 'lucide-react';

function AddProject({ user, onBack }) {
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [imageFile, setImageFile] = useState(null);
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: 'Web App',
    liveDemoUrl: ''
  });

  const categories = ['Web App', 'Mobile App', 'Game', 'AI / ML', 'IoT / Hardware'];

  const handleSubmit = async (e) => {
    e.preventDefault();
    setIsSubmitting(true);
    
    try {
      let finalImageUrl = '';

      // 1️⃣ Upload Image to Firebase Storage if selected
      if (imageFile) {
        const imageRef = ref(storage, `project_covers/${Date.now()}_${imageFile.name}`);
        await uploadBytes(imageRef, imageFile);
        finalImageUrl = await getDownloadURL(imageRef);
      }

      // 2️⃣ Save project data to Firestore
      await addDoc(collection(db, "projects"), {
        title: formData.title,
        description: formData.description,
        category: formData.category,
        imageUrl: finalImageUrl,
        liveDemoUrl: formData.liveDemoUrl,
        authorName: user?.name || 'Student',
        authorUsername: user?.username || 'unknown',
        status: 'Pending', 
        views: 0,
        createdAt: serverTimestamp()
      });
      
      alert("Project submitted successfully! Pending Admin approval.");
      onBack(); 
    } catch (error) {
      console.error("Upload error: ", error);
      alert("Failed to submit. Check Firebase Storage rules.");
    } finally {
      setIsSubmitting(false);
    }
  };

  return (
    // 🎨 Deep Purple Gradient Background to match your design
    <div className="min-h-screen bg-gradient-to-br from-[#1a103c] via-[#2d1b6e] to-[#0a0518] flex items-center justify-center p-6 font-sans selection:bg-indigo-500/30">
      
      {/* 📦 The Compact Glass Box */}
      <div className="w-full max-w-2xl bg-white/10 backdrop-blur-2xl border border-white/20 rounded-[2rem] p-8 sm:p-10 shadow-2xl relative animate-fade-in-up">
        
        {/* Close Button (Top Right) */}
        <button 
          onClick={onBack}
          className="absolute top-6 right-6 p-2 bg-white/5 hover:bg-white/10 text-gray-400 hover:text-white rounded-full transition-all border border-white/5"
        >
          <X className="w-5 h-5" />
        </button>

        <h2 className="text-3xl font-extrabold text-white mb-8">Submit Project</h2>

        <form onSubmit={handleSubmit} className="space-y-6">
          
          {/* 📸 The Dashed Upload Box (Exactly like your image) */}
          <label className="border-2 border-dashed border-white/20 hover:border-indigo-400 bg-white/5 rounded-2xl p-8 flex flex-col items-center justify-center cursor-pointer transition-all group">
            <div className="w-14 h-14 bg-black/40 rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform">
              <Camera className="w-6 h-6 text-gray-300" />
            </div>
            <span className="text-white font-bold mb-1">Click to Upload Cover Image</span>
            <span className="text-gray-400 text-sm bg-black/40 px-3 py-1 rounded-md mt-2 border border-white/5">
              {imageFile ? imageFile.name : "No file chosen"}
            </span>
            {/* Hidden native file input */}
            <input 
              type="file" 
              accept="image/*"
              onChange={(e) => setImageFile(e.target.files[0])}
              className="hidden" 
            />
          </label>

          {/* Form Fields Grid */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <input 
              type="text" required placeholder="Project Title"
              value={formData.title} onChange={(e) => setFormData({...formData, title: e.target.value})}
              className="w-full bg-black/40 border border-white/10 rounded-xl px-5 py-4 outline-none focus:border-indigo-500 text-white placeholder-gray-500 transition-all"
            />
            
            <select 
              value={formData.category} onChange={(e) => setFormData({...formData, category: e.target.value})}
              className="w-full bg-black/40 border border-white/10 rounded-xl px-5 py-4 outline-none focus:border-indigo-500 text-white appearance-none cursor-pointer transition-all"
            >
              {categories.map(cat => <option key={cat} value={cat} className="bg-[#1a103c]">{cat}</option>)}
            </select>
          </div>

          <input 
            type="url" placeholder="Project Link (URL) e.g. GitHub or Live Demo"
            value={formData.liveDemoUrl} onChange={(e) => setFormData({...formData, liveDemoUrl: e.target.value})}
            className="w-full bg-black/40 border border-white/10 rounded-xl px-5 py-4 outline-none focus:border-indigo-500 text-white placeholder-gray-500 transition-all"
          />

          <textarea 
            required rows="3" placeholder="Brief description of your project..."
            value={formData.description} onChange={(e) => setFormData({...formData, description: e.target.value})}
            className="w-full bg-black/40 border border-white/10 rounded-xl px-5 py-4 outline-none focus:border-indigo-500 text-white placeholder-gray-500 resize-none transition-all"
          ></textarea>

          {/* Action Buttons */}
          <div className="flex gap-4 pt-4">
            <button 
              type="button" onClick={onBack}
              className="w-1/3 py-4 rounded-xl font-bold text-gray-300 bg-white/5 hover:bg-white/10 border border-white/10 transition-all"
            >
              Cancel
            </button>
            <button 
              type="submit" disabled={isSubmitting}
              className={`w-2/3 py-4 rounded-xl font-bold text-white flex justify-center items-center gap-2 transition-all shadow-lg ${
                isSubmitting ? 'bg-indigo-500/50 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-500 hover:shadow-indigo-500/30'
              }`}
            >
              {isSubmitting ? <><Loader2 className="w-5 h-5 animate-spin" /> Processing...</> : <>Submit Project <Send className="w-5 h-5" /></>}
            </button>
          </div>

        </form>
      </div>
    </div>
  );
}

export default AddProject;
